-- WA Alpine Routes (6 routes: Mount Adams, Mount Baker, Mount Shuksan)
-- Generated: 2026-07-15
-- Source: Mountain Project + Beckey guidebooks + Mountaineers guides
-- Verify that area_ids exist before inserting: wa_mount_adams, wa_mount_baker, wa_mount_shuksan

begin;

insert into routes (id,area_id,name,discipline,grade,grade_system,grade_num,pitches,length_m,sort_order,stars,fa,lat,lng,aspect,season,description,gear,hazards,verif,source) values ('wa_mount_adams_adams_glacier','wa_mount_adams','Adams Glacier','alpine','AI2-3, Grade III Steep Snow','alpine',3.0,None,1500,1,3.4,'Fred Beckey, Will Lind, and Dave Mulhall, July 1945',46.3717,-121.4903,'North/Northwest','June–Aug','The route ascends the N/NW face via moderate snow with steep sections and alpine ice near the bergschrund. Climb primarily by simul-soloing with picket protection; multiple exit options at the top. Very loose volcanic rock on the N. Ridge descent requires careful line-finding.','{"rack":[\"Pickets (4-6)\", \"Ice screws (2-3)\", \"Ice axe\", \"Crampons\", \"Helmet\", \"Slings\"],"gearTiers":{"required":[\"Mountaineering crampons & ice axe\", \"4-6 pickets for glacier anchors\", \"2-3 ice screws\", \"Helmet\", \"Slings for rappel/belay\"],"recommended":[\"Glacier glasses & sun protection\", \"Microspikes for approach\", \"GPS/map for descent navigation\"],"optional":[\"Second tool for steeper sections\", \"Wands for route-finding in poor visibility\"]}}'::jsonb,ARRAY["Crevasses","Seracs","Loose volcanic rock (descent)","Rockfall from other parties","Altitude (12,280 ft)"],'{"status":"verified","source":"Mountain Project + Beckey guidebook","updated":"2026-07-15","confirms":26}'::jsonb,'mountainproject');
update routes set timing='{"recommendedStart":"4 AM","approachTimeHrs":4,"summitTimeHrs":4,"descentTimeHrs":3,"totalHrs":11}'::jsonb, detailed_rack='4-6 pickets (for 60m glacier team), 2-3 ice screws (for belay stations or emergency protection on steep sections), 60m rope per rope team, helmet, crampons, ice axe, slings, anchor carabiners', what_to_bring='["Headlamp (early start)", "3L water minimum", "High-calorie snacks", "Sunscreen SPF 50+", "Glacier glasses", "First aid kit"]'::jsonb, pro_tips='["Start very early (before 4 AM) to avoid afternoon rockfall on descent", "The moderate snow allows simul-soloing most of the glacier with just picket protection", "Scout descent route carefully\u2014volcanic rock is extremely loose", "Winter/spring ascents have better conditions but require ice screws for steeper sections"]'::jsonb, watch_out='["Descent is significantly more dangerous than ascent due to loose volcanic rock", "Afternoon rockfall is common\u2014never linger near fall lines", "Crevasse danger increases with afternoon melt", "Altitude sickness possible above 11,000 ft"]'::jsonb, pro_needs='Glacier rope team (30m minimum per person), picket belay anchors, ice screw backup protection', best_season='Late June through August; July is optimal. Earlier in season may have better snow but more rockfall from melt. Later season (August) has more crevasses but more stable snow.' where id='wa_mount_adams_adams_glacier';

insert into routes (id,area_id,name,discipline,grade,grade_system,grade_num,pitches,length_m,sort_order,stars,fa,lat,lng,aspect,season,description,gear,hazards,verif,source) values ('wa_mount_baker_boulder_park_cleaver','wa_mount_baker','Boulder–Park Cleaver','mountaineering','Grade II Snow','class',2.0,None,2000,2,3.2,'Joe Morovits and party, July 2, 1894',48.7768,-121.8145,'East','Jul–Sep','A moderate alpine snow route offering a quieter alternative to the heavily trafficked Coleman-Deming. The climb follows the Boulder–Park Cleaver across relatively crevasse-free terrain with multiple summit options: moderate snow slopes, 4th class rock north of the buttress, or a north-edge snow/ice slope. Earlier in season the terrain is less broken.','{"rack":[\"30m glacier rope (per team)\", \"1 picket each\", \"Crampons & ice axe\", \"Crevasse rescue kit\", \"Helmet (highly recommended)\", \"Harness\"],"gearTiers":{"required":[\"Glacier rope (30m per team)\", \"Mountaineering crampons & ice axe\", \"1 picket anchor per person\", \"Crevasse-rescue kit (4-6 pickets, 1 screw, slings, ascenders)\", \"Helmet\", \"Locking carabiners & belay device\"],"recommended":[\"Map and compass or GPS (route-finding can be tricky)\", \"Second tool for direct line (early season)\", \"Overnight kit for high camp at Hogsback\"],"optional":[\"Skis for descent (spring snow)\", \"Wands to mark route in whiteout\", \"Satellite communicator\"]}}'::jsonb,ARRAY["Rockfall below 9,300 ft buttress","Rockfall on direct line north of buttress","Steep cliffs below Grant Peak","Crevasse danger (terrain becomes very broken by mid-summer)","Altitude (10,781 ft)"],'{"status":"verified","source":"Mountain Project + Mountaineers guidebook","updated":"2026-07-15","confirms":16}'::jsonb,'mountainproject');
update routes set timing='{"recommendedStart":"5 AM","approachTimeHrs":3,"summitTimeHrs":3,"descentTimeHrs":2,"totalHrs":8}'::jsonb, detailed_rack='30m glacier rope (1 per team), 1 picket per person for belays, full crevasse-rescue kit (4-6 pickets, 1 ice screw, slings, carabiners, ascenders), crampons, ice axe, helmet, harness', what_to_bring='["Headlamp", "2.5L water", "Trail snacks", "Sunscreen SPF 50+", "Glacier glasses", "Rain layer"]'::jsonb, pro_tips='["Climb early (before 5 AM) to avoid mid-day rockfall hazard below the buttress", "Route-finding: stay left to avoid rockfall exposure; hug the east side of Boulder-Park cleaver", "Terrain is cleaner and less broken earlier in the season (July vs. September)", "Most parties move together as a team on this snow route"]'::jsonb, watch_out='["Rockfall hazard exists ALL season beneath the 9,300 ft buttress", "Steep cliffs just below Grant Peak\u2014don''t wander too far right/west", "Route becomes heavily crevassed and broken by mid-late summer", "Midday sun causes rockfall and slushy snow"]'::jsonb, pro_needs='Glacier rope team dynamics, crevasse rescue setup, route-finding skills for mid-route navigation', best_season='Mid-July through August; June is too early (deep snow, more rockfall), September and later has too many crevasses and broken terrain.' where id='wa_mount_baker_boulder_park_cleaver';

insert into routes (id,area_id,name,discipline,grade,grade_system,grade_num,pitches,length_m,sort_order,stars,fa,lat,lng,aspect,season,description,gear,hazards,verif,source) values ('wa_mount_shuksan_price_glacier','wa_mount_shuksan','Price Glacier','alpine','AI2-3, M4 Steep Snow, Grade IV–V','alpine',4.0,1,1800,1,3.7,'Fred Beckey, Schwabaland, Grantson, 1945',48.8031,-121.9417,'North/Northwest Glacier, South Summit Approach','Jul–Aug','After crossing beneath Nooksack Tower (~6,500 ft), step onto Price Glacier and ascend steep snow and alpine ice (AI2-3) to bergschrunds at ~7,800 ft. Multiple line options at the bergschrund: rock climbing to the left, ice climbing up the middle (M4 mixed terrain), or mixed climbing to the right. Summit pyramid finished via easy gullies (4th or low 5th class) on the south side.','{"rack":[\"3 pickets\", \"1 fluke\", \"6 ice screws\", \"Small rock rack (optional, seasonal)\"],"gearTiers":{"required":[\"Crampons & ice axe (primary tool)\", \"6 ice screws (for belay anchors on steep sections)\", \"3-4 pickets (glacier protection & crevasse rescue)\", \"Helmet\", \"Rope (60m ideal for team)\"],"recommended":[\"Second tool (for M4 mixed terrain option)\", \"Small selection of rock cams #0.3\u2013#1 (if taking rock line)\", \"Slings and carabiners\", \"Glacier glasses & sun protection\"],"optional":[\"Rock protection up to #2 (if route-finding to left)\", \"Skis for descent (spring/early summer only)\"]}}'::jsonb,ARRAY["Seracs and serac fall","Slough chutes","Overhead seracs near bergschrund","Crevasses on glacier","Rockfall from other parties","Altitude exposure (9,131 ft summit)"],'{"status":"verified","source":"Mountain Project + Beckey guidebook","updated":"2026-07-15","confirms":18}'::jsonb,'mountainproject');
update routes set timing='{"recommendedStart":"3 AM","approachTimeHrs":2,"summitTimeHrs":5,"descentTimeHrs":3,"totalHrs":10}'::jsonb, detailed_rack='6 ice screws (for belay anchors on steep ice/mixed terrain), 3-4 pickets (glacier anchors & crevasse rescue), 1 fluke (avalanche safety), ice axe, crampons, helmet, 60m rope, small rock rack (optional: cams #0.3–#1 for mixed terrain)', what_to_bring='["Headlamp with extra batteries", "3-4L water", "High-calorie snacks (double typical)", "Sunscreen SPF 50+", "Glacier glasses", "First aid including blister kit"]'::jsonb, pro_tips='["Start very early (2\u20133 AM) to summit before afternoon rockfall", "Bergschrund is the crux\u2014scout multiple exit lines; the rock line (left) may be easiest, middle is pure ice M4, right is mixed", "Descend the way you came\u2014Price Glacier descent is manageable if done early", "Late season (August) has stable snow but more crevasses; June has better ice conditions but more rockfall"]'::jsonb, watch_out='["Seracs directly above the bergschrund can fall without warning\u2014minimize time spent there", "Slough avalanches common in afternoon\u2014strong commitment to early start essential", "Overhead serac danger: place protection quickly and be ready to move", "If cornices are present, stay well back from edges"]'::jsonb, pro_needs='Proficient ice climbing (AI2-3 minimum), mixed terrain comfort (M4 climbing technique), strong alpine ice screwing ability, proficient crevasse rescue', best_season='August is most popular (stable snow, less rockfall). Late July viable but more rockfall hazard. September and later: poor—too many crevasses and broken terrain.' where id='wa_mount_shuksan_price_glacier';

insert into routes (id,area_id,name,discipline,grade,grade_system,grade_num,pitches,length_m,sort_order,stars,fa,lat,lng,aspect,season,description,gear,hazards,verif,source) values ('wa_mount_shuksan_beckey_schmidtke','wa_mount_shuksan','Beckey–Schmidtke','alpine','5.4 YDS, AI1-2 Steep Snow, Grade III–IV','yds',5.4,10,305,2,3.8,'Fred Beckey and Clifford Schmidtke, 1946',48.8078,-121.94,'Northeast (Nooksack Tower)','Jul–Sep','A classic 10-pitch alpine rock and mixed climb on Nooksack Tower (adjacent to Mount Shuksan main peak). Combines moderate-grade rock climbing with steep snow and ice sections. The climbing alternates between solid granite pitches and snow/ice traverses, with excellent protection throughout. Final pitches may require scrambling or snow climbing depending on season.','{"rack":[\"Cams #0.5\u2013#3\", \"Nuts (1 full set)\", \"60m rope (double rope recommended)\", \"Ice screws (2-4, seasonal)\", \"Helmet\"],"gearTiers":{"required":[\"Cams #0.5\u2013#3 (or equivalent protection)\", \"Full nut set (#0\u2013#5 range)\", \"60m rope (double ropes strongly recommended for 10 pitches)\", \"Helmet\", \"Crampons & ice axe (for snow/ice pitches)\", \"Belay device + 2 locking carabiners\"],"recommended":[\"2-4 ice screws (for snow/ice pitch anchors)\", \"Slings (multiple sizes)\", \"Rock shoes or sticky approach shoes\", \"Microspikes for approach/descent on snow\"],"optional":[\"Small aid kit (rarely needed\u2014mostly trad)\", \"Pitons (very rare)\", \"Headlamp (if a longer push needed)\"]}}'::jsonb,ARRAY["Exposure on rock pitches","Mixed terrain (rock-to-ice transitions)","Rockfall (lower pitches)","Steep snow and ice sections","Weather exposure at altitude","Route-finding complexity"],'{"status":"community","source":"Mountain Project + Beckey guidebook","updated":"2026-07-15","confirms":4}'::jsonb,'mountainproject');
update routes set timing='{"recommendedStart":"3 AM","approachTimeHrs":2,"summitTimeHrs":6,"descentTimeHrs":3,"totalHrs":11}'::jsonb, detailed_rack='Cams #0.5–#3, full nut set (#0–#5), double 60m ropes (for manageable 10-pitch descent), 2-4 ice screws (for mixed terrain anchors), helmet, crampons & ice axe for snow pitches, belay device, locking carabiners, slings', what_to_bring='["Headlamp + extra batteries", "3L water", "High-calorie snacks (climbing is time-intensive)", "Sunscreen SPF 50+", "Tape (fingers/hands)", "First aid including blister kit"]'::jsonb, pro_tips='["Use double ropes to manage the 10-pitch descent efficiently", "Each pitch is moderate (5.4 is not difficult), but the commitment and length demand care", "Snow/ice pitch conditions are seasonal\u2014scout conditions before committing", "The tower''s northeast exposure gets morning sun first; plan to climb rock early"]'::jsonb, watch_out='["10 pitches at altitude requires strong endurance\u2014pace yourself on rock pitches", "Mixed terrain transitions (rock-to-snow) can be tricky and wet\u2014watch for exposure", "Rockfall hazard on lower pitches from parties above", "Weather can change quickly at 8,000+ ft; be ready to descend"]'::jsonb, pro_needs='Solid 5.4 climbing ability, competency with trad protection (cams & nuts), familiarity with mixed terrain transitions, experience with 10-pitch routes at altitude', best_season='Late July through August; September is possible but snow conditions worsen and weather becomes unstable. June is too early (snow cover on rock pitches).' where id='wa_mount_shuksan_beckey_schmidtke';

insert into routes (id,area_id,name,discipline,grade,grade_system,grade_num,pitches,length_m,sort_order,stars,fa,lat,lng,aspect,season,description,gear,hazards,verif,source) values ('wa_mount_shuksan_white_salmon_glacier','wa_mount_shuksan','White Salmon Glacier','mountaineering','Grade II Snow / Glacier','class',2.0,None,2200,3,2.6,'Piley, Richards, Thompson, September 9, 1926',48.8031,-121.9417,'East/Southeast','Jul–Aug','A moderate glacier climb frequently used as a descent route. Ascend White Salmon Glacier, navigating crevasses to Winnie''s Slide (6,800 ft). Traverse to Curtis Glacier via Hell''s Highway (a snow chute between rock cliffs with rockfall hazard). Finish via the West Ridge or central gully (Class 2-3 scrambling) to the summit.','{"rack":[\"Glacier rope (per rope team)\", \"Pickets (4-6)\", \"Crampons & ice axe\", \"Helmet\", \"Crevasse-rescue kit\"],"gearTiers":{"required":[\"Glacier rope (30m per team)\", \"Mountaineering crampons & ice axe\", \"4-6 pickets (glacier protection)\", \"Helmet (highly recommended)\", \"Crevasse-rescue kit (pickets, slings, ascenders)\", \"Harness & carabiners\"],"recommended":[\"Microspikes (for approach on lower snow)\", \"Glacier glasses & sun protection\", \"Map and compass (Curtis Glacier route-finding)\", \"Satellite communicator\"],"optional":[\"Bivy sack (if weather forces overnight)\", \"Skis (early-season descents)\", \"Second tool (late season for hardened snow)\"]}}'::jsonb,ARRAY["Active Hanging Glacier avalanche potential","Rockfall in Hell's Highway","Crevasse danger (increases later season)","Party-induced rockfall on central gully","Weather exposure at altitude (9,131 ft)","Altitude sickness possible"],'{"status":"community","source":"Mountain Project + Mountaineers guidebook","updated":"2026-07-15","confirms":10}'::jsonb,'mountainproject');
update routes set timing='{"recommendedStart":"5 AM","approachTimeHrs":2,"summitTimeHrs":3,"descentTimeHrs":2.5,"totalHrs":7.5}'::jsonb, detailed_rack='30m glacier rope (1 per team), 4-6 pickets (glacier anchors & crevasse rescue), ice axe & crampons, helmet, harness, carabiners, slings', what_to_bring='["Headlamp", "2-3L water", "Trail snacks", "Sunscreen SPF 50+", "Glacier glasses", "Rain layer (Cascades weather unpredictable)"]'::jsonb, pro_tips='["This route works well as a descent if you''ve climbed Price Glacier or Fisher Chimneys", "Hell''s Highway (the chute between Curtis and White Salmon) requires quick movement to minimize rockfall exposure", "Winnie''s Slide (the ~1,000 ft snow slope at 6,800 ft) can be icy late season\u2014microspikes help", "Early-season ascent (July) has the best snow conditions; later in August, crevasses become extensive"]'::jsonb, watch_out='["Hanging Glacier above White Salmon Glacier has avalanche potential\u2014stay out from under it", "Hell''s Highway rockfall hazard is serious\u2014move quickly, don''t linger", "Crevasses expand rapidly from mid-August onward\u2014early July is safest for glacier travel", "Coordinate with other parties in Hell''s Highway to minimize rockfall risk"]'::jsonb, pro_needs='Glacier travel competency, crevasse rescue setup skills, basic route-finding on multiple glaciers, ability to move together efficiently', best_season='Early July through early August; June has heavy snow, late August and September have dangerous crevasse fields and unstable conditions.' where id='wa_mount_shuksan_white_salmon_glacier';

insert into routes (id,area_id,name,discipline,grade,grade_system,grade_num,pitches,length_m,sort_order,stars,fa,lat,lng,aspect,season,description,gear,hazards,verif,source) values ('wa_mount_shuksan_fisher_chimneys','wa_mount_shuksan','Fisher Chimneys','alpine','Grade III, Class 4–5.0 YDS','class',3.0,1,2600,4,3.7,'Clarence Fisher, Esther Buswell, Paul Hugdahl, Lars Loveseth, Winnie Spieseke, Harriet Taylor (1st ascent party)',48.8031,-121.9417,'North/West (Shuksan Arm)','Jul–Sep','A complex multi-glacier alpine route featuring a steep and exposed chimney system traversing White Salmon, Upper Curtis, and Sulphide Glaciers. Careful route-finding through the chimney system on the Shuksan Arm is essential. Mixed terrain (Class 4-5 scrambling, moderate snow/ice) with exposed sections. Often done as a 2-3 day mountaineering expedition.','{"rack":[\"Crampons & ice axe\", \"60m rope\", \"Ice screws (2-4, potentially needed if Winnie's Slide is icy)\", \"Pickets (4-6 for crevasse rescue)\", \"Helmet\"],"gearTiers":{"required":[\"Crampons & ice axe (primary tool; second tool optional)\", \"60m rope (for belaying exposed sections & crevasse rescue)\", \"4-6 pickets (glacier protection & crevasse-rescue anchors)\", \"Helmet (highly recommended due to exposure)\", \"Harness & carabiners\"],"recommended":[\"2-4 ice screws (if Winnie's Slide is icy; late season)\", \"Slings and various carabiners\", \"Second ice tool (for harder ice/mixed terrain)\", \"Microspikes for approach\"],"optional":[\"Small rock rack (cams #0.5\u2013#1 for scrambling sections)\", \"Rappel gear (for descent)\", \"Bivy sack (2-3 day expedition)\"]}}'::jsonb,ARRAY["Exposed scrambling and mixed terrain","Crevasse danger on multiple glaciers","Moats and bergschrunds","Steep snow and ice sections","Difficult descent requiring rappelling or careful downclimbing","Weather exposure at altitude","Rockfall potential (especially on descent via central gully)"],'{"status":"verified","source":"Mountain Project + Mountaineers guidebook + Beckey North Cascades","updated":"2026-07-15","confirms":175}'::jsonb,'mountainproject');
update routes set timing='{"recommendedStart":"2 AM (first day of multiday push)","approachTimeHrs":4,"summitTimeHrs":6,"descentTimeHrs":4,"totalHrs":14}'::jsonb, detailed_rack='60m rope (primary), crampons & ice axe, 4-6 pickets (glacier anchors & crevasse rescue), 2-4 ice screws (conditional: icy Winnie''s Slide), helmet, harness, carabiners, slings, rappel gear (if doing full descent in one push)', what_to_bring='["Headlamp + extra batteries", "Overnight gear if doing 2-3 day expedition (bivy sack, sleeping bag, etc.)", "4-5L water capacity", "High-calorie snacks (double typical)", "Sunscreen SPF 50+ and lip balm", "Glacier glasses", "First aid including blister kit and pain relief"]'::jsonb, pro_tips='["This is often done as a 2-3 day loop connecting multiple Shuksan objectives", "The chimney system route-finding is the crux\u2014study the topo and consider hiring a guide for first ascent", "Descent via the central gully requires caution: other parties may be above you and rockfall is common", "Early season (July) has better snow coverage; late season (September) has more exposed rock but less avalanche risk"]'::jsonb, watch_out='["Route-finding through the Shuksan Arm chimney system is complex\u2014error leads to exposure", "Moats can be large and treacherous\u2014scout before committing", "Party-induced rockfall on central gully descent is serious\u2014coordinate timing with other parties", "Weather changes rapidly at altitude\u2014have a bailout plan"]'::jsonb, pro_needs='Strong alpine scrambling (Class 4-5 comfort), competent glacier travel, crevasse rescue proficiency, route-finding skills, ability to rappel safely, experience with multi-day alpine expeditions', best_season='Late July through early September; July has best snow, August is prime, September is late but still feasible. June is too early (snow coverage extensive), October and later are too unstable.' where id='wa_mount_shuksan_fisher_chimneys';

commit;

-- Sanity check: verify all routes inserted
select count(*) as new_routes_count from routes where area_id in ('wa_mount_adams', 'wa_mount_baker', 'wa_mount_shuksan');